}

public PurchLine parmPurchLine(PurchLine _purchLine = purchLine)
{
    purchLine = _purchLine;

    return purchLine;
}

public boolean parmCalledFromProductReceipt(boolean _calledFromProductReceipt = calledFromProductReceipt)
{
    calledFromProductReceipt = _calledFromProductReceipt;

    return calledFromProductReceipt;
}

public TmpInventTransWMS parmTmpInventTransWMS(TmpInventTransWMS _inventTransWMS = inventTransWMS)
{
    inventTransWMS = _inventTransWMS;

    return inventTransWMS;
}

public PurchParmLine parmPurchParmLine(PurchParmLine _purchParmLine = purchParmLine)
{
    purchParmLine = _purchParmLine;

    return purchParmLine;
}

public InventDim parmInventDim(InventDim _inventDim = inventDim)
{
    inventDim = _inventDim;

    return inventDim;
}

public FormDataSource parmFormDataSource(FormDataSource _formDS = formDS)
{
    formDS = _formDS;

    return formDS;
}

