public void processPurchaseOrder()
{
    InventTRansOrigin inventTransOrigin;
    InventTrans InventTrans;
    inventDim inventDimNew;
  //  MultiSelectionHelper selectionHelper = MultiSelectionHelper::construct();
  //  selectionHelper.parmDatasource(formDS);
    inventTransWMS = formDS.getFirst() as TmpInventTransWMS;// formDS.cursor() as TmpInventTransWMS;

    PurchTable purchTable = purchLine.purchTable();

    ttsbegin;

    while (inventTransWMS)
    {
        inventTransOrigin = inventTransOrigin::find(inventTransWMS.InventTransOrigin);
        purchLine         = PurchLine::findInventTransId(inventTransOrigin.InventTransId, true);

        purchLineNew.clear();
        inventDimNew.clear();

        //CS, DLT, SB, 30/04/2026 MultiLine apply rate bug fix -> Buf2buf is not applicable for split & dockage item 
        if(inventTransWMS.ItemId == purchLine.ItemId)
        {
            buf2Buf(purchLine, purchLineNew);
        }
        purchLineNew.initFromPurchTable(purchTable);
        //CE, DLT, SB

        purchLineNew.ItemId     = inventTransWMS.ItemId;
        purchLineNew.LineNumber = purchLine.nextLineNum();
        purchLineNew.modifiedField(fieldNum(PurchLine, ItemId));
        purchLineNew.PurchQty = inventTransWMS.InventQty;
        //CS - Abhinav
        purchLineNew.initFromInventTable(InventTable::find(inventTransWMS.ItemId));
        purchLineNew.PurchPrice = inventTransWMS.ETGRateCardUnitPrice;

        //CE
        if(purchLineNew.LinePercent == 0 && inventTransWMS.ETGRateCardDiscPct != 0)
        {
            purchLineNew.LinePercent = inventTransWMS.ETGRateCardDiscPct;
        }
        if(purchLineNew.LineDisc == 0 && inventTransWMS.ETGRateCardDiscAmount != 0)
        {
            purchLineNew.LineDisc = inventTransWMS.ETGRateCardDiscAmount;
        }
        purchLineNew.LineAmount = inventTransWMS.ETGRateCardLineAmount;

        inventDimNew            = InventDim::findOrCreate(inventDim::find(inventTransWMS.InventDimId));

        //CS, DLT, SB, Assign Custom BatchId
        inventDimNew.inventBatchId  = InventTable::find(inventTransWMS.ItemId).ETGDefaultBatchNumber;
        //CE, DLT, SB

        purchLineNew.InventDimId = InventDim::findOrCreate(inventDimNew).inventDimId;
        purchLineNew.modifiedField(fieldNum(PurchLine, InventDimId));
        purchLineNew.initVariantId(inventDimNew);
        //if(purchLineNew.InventDimId != inventDimNew.inventDimId)
        //{
        //    purchLineNew.InventDimId = inventDimNew.inventDimId;
        //    purchLineNew.modifiedField(fieldNum(PurchLine, InventDimId));
        //}

        //inventDimNew            = InventDim::findOrCreate(inventDim);

        //if(purchLineNew.InventDimId != inventDimNew.inventDimId)
        //{
        //    purchLineNew.InventDimId = inventDimNew.inventDimId;
        //    purchLineNew.modifiedField(fieldNum(PurchLine, InventDimId));
        //}

        if(purchLineNew.validateWrite())
        {
            purchTable.reread();
            purchTable.selectForUpdate(true);
            purchTable.DocumentState = VersioningDocumentState::Draft;
            purchTable.update();
            //purchLineNew.InventTransId        = NumberSeq::newGetNum(InventParameters::numRefInventTransId()).num();
            purchLineNew.RemainInventPhysical = inventTransWMS.InventQty;
            purchLineNew.RemainPurchPhysical  = inventTransWMS.InventQty;
            purchLineNew.ETGRateCardApplied   = NoYes::Yes;
            purchLineNew.WorkflowState        = TradeWorkflowState::Approved;

            //CS - Abhinav - Enable is Dockage/Split boolean on purchLine From Elevator receipt
            if(ETGCanadaParameters::find().EnableRateCardChanges && purchTable.ETGElevatorReceiptNumber)
            {
                changecompany(purchTable.ETGERNEntity)
                {
                    ETGElevatorReceiptSplitsItemTable   etgElevatorReceiptSplitsItemTable;
                    ETGElevatorReceiptTable             etgElevatorReceiptTable;

                    select firstonly etgElevatorReceiptSplitsItemTable
                        where etgElevatorReceiptSplitsItemTable.ElevatorReceiptNumber == purchTable.ETGElevatorReceiptNumber
                        && etgElevatorReceiptSplitsItemTable.ItemId == purchLineNew.ItemId;

                    if(etgElevatorReceiptSplitsItemTable)
                    {
                        purchLineNew.ETGIsSplitItem = NoYes::Yes;
                    }

                    select firstonly etgElevatorReceiptTable
                        where etgElevatorReceiptTable.ElevatorReceiptNumber == purchTable.ETGElevatorReceiptNumber;

                    if(etgElevatorReceiptTable.DockageGrain == purchLineNew.ItemId)
                    {
                        purchLineNew.ETGIsDockageItem = NoYes::Yes;
                    }
                }
            }
            //CE - Abhinav

            purchLineNew.insert();
            //allocate charges to new purchline
            this.allocateChargesToNewPurchaseLine();

        }
        else
        {
            ttsabort;
            throw Error("Error. Purchase rate card is not applied.");
        }
        inventTransWMS = formDS.getNext() as TmpInventTransWMS;
    }


    //cancel old purchline qty
    this.cancelPurchLineQty();


    PurchTableVersion purchTableVersion = PurchTableVersion::findLatest(purchTable.PurchId, purchTable.DataAreaId, true);
    if(purchTableVersion)
    {
        purchTableVersion.IsArchived = NoYes::Yes;
        purchTableVersion.update();
    }

    if(inventTransOrigin)
    {
        delete_from InventTrans where inventTrans.InventTransOrigin == inventTransOrigin.RecId;
    }

    purchTable.autoApproveChangeRequest(true);


    ttscommit;
}

public PurchLine processPurchaseOrderGRNUploader(InventTransId inventTransId, ETGGRNUploaderTmp uploadTmp)
{
    ETGRateCardMaster rateCardMaster;
    InventDim inventDimNew;
    DiscAmount totalDiscAmt;
    inventTransOrigin inventTransOrigin;
    InventTrans inventTrans;
    LineAmount        priceAfterCashDisc, priceAfterDiscPercent;
    DiscPct           totalDiscPct;

    select firstonly rateCardMaster where rateCardMaster.RateCardId == uploadTmp.RateCardId;

    purchLine = PurchLine::findInventTransId(inventTransId, true);

    //CS, Vinay, DLT rate card 29012025
    buf2Buf(purchLine, purchLineNew);

    ttsbegin;

    purchLineNew.ItemId     = rateCardMaster.ItemId;
    purchLineNew.LineNumber = purchLine.nextLineNum();
    priceAfterCashDisc      = purchLine.PurchPrice;

    priceAfterCashDisc      = priceAfterCashDisc - (rateCardMaster.DiscAmount + purchLine.LineDisc);
    purchLineNew.DiscAmount = rateCardMaster.DiscAmount + purchLine.LineDisc;
    purchLineNew.LineAmount = priceAfterCashDisc * purchLine.PurchQty;
    totalDiscPct              = rateCardMaster.DiscPct + purchLine.LinePercent;
    priceAfterDiscPercent     = priceAfterCashDisc - (priceAfterCashDisc * totalDiscPct) / 100;
    purchLineNew.LinePercent  = totalDiscPct;
    purchLineNew.LineAmount   = priceAfterDiscPercent * purchLine.PurchQty;
    inventDimNew                  = purchLine.inventDim();
    inventDimNew.configId         = rateCardMaster.configId;
    inventDimNew.InventColorId    = rateCardMaster.InventColorId;
    inventDimNew.InventSizeId     = rateCardMaster.InventSizeId;
    inventDimNew.InventStyleId    = rateCardMaster.InventStyleId;
    inventDimNew.inventBatchId    = uploadTmp.inventBatchId;
    inventDimNew.inventSerialId   = uploadTmp.inventSerialId;
    inventDimNew.InventSiteId     = uploadTmp.InventSiteId;
    inventDimNew.InventLocationId = uploadTmp.InventLocationId;
    inventDimNew.wMSLocationId    = uploadTmp.wMSLocationId;
    inventDimNew                  = InventDim::findOrCreate(inventDimNew);

    if(purchLineNew.InventDimId != inventDimNew.inventDimId)
    {
        purchLineNew.InventDimId = inventDimNew.inventDimId;
        purchLineNew.modifiedField(fieldNum(PurchLine, InventDimId));
    }

    purchLineNew.VariantId = rateCardMaster.RetailVariantId;
    purchLineNew.modifiedField(fieldNum(PurchLine, VariantId));

    if(purchLineNew.validateWrite())
    {
        PurchTable purchTable = purchLineNew.purchTable();
        purchTable.reread();
        purchTable.selectForUpdate(true);
     //   purchTable.DocumentState = VersioningDocumentState::Draft;
        purchTable.update();

        purchLineNew.InventTransId = NumberSeq::newGetNum(InventParameters::numRefInventTransId()).num();
        purchLineNew.RemainInventPhysical = purchLineNew.PurchQty;
        purchLineNew.RemainPurchPhysical  = purchLineNew.PurchQty;
        purchLineNew.ETGRateCardApplied = NoYes::Yes;
        purchLineNew.WorkflowState = TradeWorkflowState::Approved;
        purchLineNew.insert();

        //allocate charges to new purchline
        this.allocateChargesToNewPurchaseLine();

        //cancel old purchline qty
        this.cancelPurchLineQty();

        PurchTableVersion purchTableVersion = PurchTableVersion::findLatest(purchTable.PurchId, purchTable.DataAreaId, true);
        if(purchTableVersion)
        {
            purchTableVersion.IsArchived = NoYes::Yes;
            purchTableVersion.update();
        }

        inventTransOrigin = InventTransOrigin::findByInventTransId(purchLine.InventTransId);
        if(inventTransOrigin)
        {
            delete_from InventTrans where inventTrans.InventTransOrigin == inventTransOrigin.RecId;
        }

        purchTable.autoApproveChangeRequest(true);

        PurchFormLetter purchFormLetter = PurchFormLetter::construct(DocumentStatus::PurchaseOrder);
        PurchaseOrderId purchOrderDocNum = strFmt('%1-%2', purchTable.PurchId, VendPurchOrderJour::numberOfPurchaseOrderVersions(purchTable)+1);
        purchFormLetter.update(purchTable, purchOrderDocNum);

        purchFormLetter = PurchFormLetter::construct(DocumentStatus::PackingSlip);
        purchOrderDocNum = strFmt('%1-%2', purchTable.PurchId, VendPurchOrderJour::numberOfPurchaseOrderVersions(purchTable)+2);
        purchFormLetter.update(purchTable, purchOrderDocNum);
    }
    else
    {
        warning(strFmt("Error. Rate card is not applied for purchase order %1", purchLine.PurchId));
    }

    ttscommit;



    return purchLineNew;
}

public void allocateChargesToNewPurchaseLine()
{
    MarkupTrans markUpTrans, markUpTransUpd;

    select firstonly RecId from markUpTrans
        where markUpTrans.TransRecId == purchLine.RecId
        && markUpTrans.TransTableId == purchLine.TableId;

    if(markUpTrans.RecId)
    {
        update_recordset markUpTransUpd
            setting TransRecId = purchLineNew.RecId
        where markUpTransUpd.TransRecId == purchLine.RecId
            && markUpTransUpd.TransTableId == purchLine.TableId
            && markUpTransUpd.DataAreaId == purchLine.DataAreaId;
    }
}

public void cancelPurchLineQty()
{
    purchLine.reread();
    purchLine.selectForUpdate(true);
    purchLine.RemainInventPhysical  = 0;
    purchLine.PurchQty              = 0;
    purchLine.QtyOrdered            = 0;
    purchLine.LineAmount            = 0;
    purchLine.RemainPurchPhysical   = 0;
    purchLine.PurchStatus = PurchStatus::Canceled;
    purchLine.updateWorkflowState(TradeWorkflowState::Submitted);
    purchLine.update();
    InventMovement::bufferSetRemainQty(purchLine);
}

public void processProductReceipt()
{
    inventTransWMS = formDS.cursor() as TmpInventTransWMS;

    if(!inventTransWMS)
    {
        return;
    }
    purchParmLine.selectForUpdate(true);
    ttsbegin;

    purchParmLine.PurchPrice = inventTransWMS.ETGRateCardUnitPrice;
    if(inventTransWMS.InventDimId != purchParmLine.InventDimId)
    {
        purchParmLine.InventDimId = inventTransWMS.InventDimId;
        purchParmLine.modifiedField(fieldNum(PurchParmLine, InventDimId));
    }

    if(purchParmLine.validateWrite())
    {
        purchParmLine.ETGRateCardApplied = NoYes::Yes;
        purchParmLine.update();
    }
    else
    {
        ttsabort;
        info("Error. Purchase rate card is not applied.");
    }
    ttscommit;
}

public void run()
{
    if(!calledFromProductReceipt)
    {
        PurchTable purchTable = purchLine.purchTable();
        this.processPurchaseOrder();
        PurchFormLetter purchFormLetter = PurchFormLetter::construct(DocumentStatus::PurchaseOrder);
        PurchaseOrderId purchOrderDocNum = strFmt('%1-%2', purchTable.PurchId, VendPurchOrderJour::numberOfPurchaseOrderVersions(purchTable)+1);
        purchFormLetter.update(purchTable, purchOrderDocNum);
    }
    else if(calledFromProductReceipt)
    {
        PurchTable purchTable;
        purchTable = purchParmLine.purchTable();
        this.parmPurchLine(purchParmLine.purchLine());
        this.processPurchaseOrder();
        PurchFormLetter purchFormLetter = PurchFormLetter::construct(DocumentStatus::PurchaseOrder);
        PurchaseOrderId purchOrderDocNum = strFmt('%1-%2', purchTable.PurchId, VendPurchOrderJour::numberOfPurchaseOrderVersions(purchTable)+1);
        purchFormLetter.update(purchTable, purchOrderDocNum);
        this.processProductReceipt();
    }

}
